window.BIBLE["Amos"] = {"1":{"chapter":"1","title":"JUDGMENT ON THE NATIONS","verses":{"1":{"text":"The words of Amos, who was among the herdmen of Tekoa, which he saw concerning Israel in the days of Uzziah king of Judah, and in the days of Jeroboam the son of Joash king of Israel, two years before the earthquake.","ref":"Amos 1:1","synthesized":"These are the words of Amos, who was among the sheepherders of Tekoa—what he saw concerning Israel two years before the earthquake, in the days when Uzziah was king of Judah and Jeroboam son of Jehoash was king of Israel.","sources":{"KJV":{"text":"The words of Amos, who was among the herdmen of Tekoa, which he saw concerning Israel in the days of Uzziah king of Judah, and in the days of Jeroboam the son of Joash king of Israel, two years before the earthquake."},"BSB":{"text":"These are the words of Amos, who was among the sheepherders of Tekoa—what he saw concerning Israel two years before the earthquake, in the days when Uzziah was king of Judah and Jeroboam son of Jehoash was king of Israel."}},"definableWords":["saw","Israel","years","days","king","Judah","son","King"],"peopleInVerse":[]},"2":{"text":"And he said, The LORD will roar from Zion, and utter his voice from Jerusalem; and the habitations of the shepherds shall mourn, and the top of Carmel shall wither.","ref":"Amos 1:2","synthesized":"He said:  “The LORD roars from Zion and raises His voice from Jerusalem; the pastures of the shepherds mourn, and the summit of Carmel withers.”","sources":{"KJV":{"text":"And he said, The LORD will roar from Zion, and utter his voice from Jerusalem; and the habitations of the shepherds shall mourn, and the top of Carmel shall wither."},"BSB":{"text":"He said:  “The LORD roars from Zion and raises His voice from Jerusalem; the pastures of the shepherds mourn, and the summit of Carmel withers.”"}},"definableWords":["LORD","Zion","voice","Jerusalem"],"peopleInVerse":[]},"3":{"text":"Thus saith the LORD; For three transgressions of Damascus, and for four, I will not turn away the punishment thereof; because they have threshed Gilead with threshing instruments of iron:","ref":"Amos 1:3","synthesized":"This is what the LORD says:  “For three transgressions of Damascus, even four, I will not revoke My judgment, because they threshed Gilead with sledges of iron.","sources":{"KJV":{"text":"Thus saith the LORD; For three transgressions of Damascus, and for four, I will not turn away the punishment thereof; because they have threshed Gilead with threshing instruments of iron:"},"BSB":{"text":"This is what the LORD says:  “For three transgressions of Damascus, even four, I will not revoke My judgment, because they threshed Gilead with sledges of iron."}},"definableWords":["LORD","judgment"],"peopleInVerse":[]},"4":{"text":"But I will send a fire into the house of Hazael, which shall devour the palaces of Benhadad.","ref":"Amos 1:4","synthesized":"So I will send fire upon the house of Hazael to consume the citadels of Ben-hadad.","sources":{"KJV":{"text":"But I will send a fire into the house of Hazael, which shall devour the palaces of Benhadad."},"BSB":{"text":"So I will send fire upon the house of Hazael to consume the citadels of Ben-hadad."}},"definableWords":["house"],"peopleInVerse":[]},"5":{"text":"I will break also the bar of Damascus, and cut off the inhabitant from the plain of Aven, and him that holdeth the sceptre from the house of Eden: and the people of Syria shall go into captivity unto Kir, saith the LORD.","ref":"Amos 1:5","synthesized":"I will break down the gates of Damascus; I will cut off the ruler of the Valley of Aven and the one who wields the scepter in Beth-eden. The people of Aram will be exiled to Kir,” says the LORD.","sources":{"KJV":{"text":"I will break also the bar of Damascus, and cut off the inhabitant from the plain of Aven, and him that holdeth the sceptre from the house of Eden: and the people of Syria shall go into captivity unto Kir, saith the LORD."},"BSB":{"text":"I will break down the gates of Damascus; I will cut off the ruler of the Valley of Aven and the one who wields the scepter in Beth-eden. The people of Aram will be exiled to Kir,” says the LORD."}},"definableWords":["ruler","one","scepter","eden","people","LORD"],"peopleInVerse":[]},"6":{"text":"Thus saith the LORD; For three transgressions of Gaza, and for four, I will not turn away the punishment thereof; because they carried away captive the whole captivity, to deliver them up to Edom:","ref":"Amos 1:6","synthesized":"This is what the LORD says:  “For three transgressions of Gaza, even four, I will not revoke My judgment, because they exiled a whole population, delivering them up to Edom.","sources":{"KJV":{"text":"Thus saith the LORD; For three transgressions of Gaza, and for four, I will not turn away the punishment thereof; because they carried away captive the whole captivity, to deliver them up to Edom:"},"BSB":{"text":"This is what the LORD says:  “For three transgressions of Gaza, even four, I will not revoke My judgment, because they exiled a whole population, delivering them up to Edom."}},"definableWords":["LORD","judgment","Edom"],"peopleInVerse":[]},"7":{"text":"But I will send a fire on the wall of Gaza, which shall devour the palaces thereof:","ref":"Amos 1:7","synthesized":"So I will send fire upon the walls of Gaza, to consume its citadels.","sources":{"KJV":{"text":"But I will send a fire on the wall of Gaza, which shall devour the palaces thereof:"},"BSB":{"text":"So I will send fire upon the walls of Gaza, to consume its citadels."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"And I will cut off the inhabitant from Ashdod, and him that holdeth the sceptre from Ashkelon, and I will turn mine hand against Ekron: and the remnant of the Philistines shall perish, saith the Lord GOD.","ref":"Amos 1:8","synthesized":"I will cut off the ruler of Ashdod and the one who wields the scepter in Ashkelon. I will turn My hand against Ekron, and the remnant of the Philistines will perish,” says the Lord GOD.","sources":{"KJV":{"text":"And I will cut off the inhabitant from Ashdod, and him that holdeth the sceptre from Ashkelon, and I will turn mine hand against Ekron: and the remnant of the Philistines shall perish, saith the Lord GOD."},"BSB":{"text":"I will cut off the ruler of Ashdod and the one who wields the scepter in Ashkelon. I will turn My hand against Ekron, and the remnant of the Philistines will perish,” says the Lord GOD."}},"definableWords":["ruler","one","scepter","remnant","Lord","God"],"peopleInVerse":[]},"9":{"text":"Thus saith the LORD; For three transgressions of Tyrus, and for four, I will not turn away the punishment thereof; because they delivered up the whole captivity to Edom, and remembered not the brotherly covenant:","ref":"Amos 1:9","synthesized":"This is what the LORD says:  “For three transgressions of Tyre, even four, I will not revoke My judgment, because they delivered up a whole congregation of exiles to Edom and broke a covenant of brotherhood.","sources":{"KJV":{"text":"Thus saith the LORD; For three transgressions of Tyrus, and for four, I will not turn away the punishment thereof; because they delivered up the whole captivity to Edom, and remembered not the brotherly covenant:"},"BSB":{"text":"This is what the LORD says:  “For three transgressions of Tyre, even four, I will not revoke My judgment, because they delivered up a whole congregation of exiles to Edom and broke a covenant of brotherhood."}},"definableWords":["LORD","judgment","Edom","covenant"],"peopleInVerse":[]},"10":{"text":"But I will send a fire on the wall of Tyrus, which shall devour the palaces thereof.","ref":"Amos 1:10","synthesized":"So I will send fire upon the walls of Tyre to consume its citadels.”","sources":{"KJV":{"text":"But I will send a fire on the wall of Tyrus, which shall devour the palaces thereof."},"BSB":{"text":"So I will send fire upon the walls of Tyre to consume its citadels.”"}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"Thus saith the LORD; For three transgressions of Edom, and for four, I will not turn away the punishment thereof; because he did pursue his brother with the sword, and did cast off all pity, and his anger did tear perpetually, and he kept his wrath for ever:","ref":"Amos 1:11","synthesized":"This is what the LORD says:  “For three transgressions of Edom, even four, I will not revoke My judgment, because he pursued his brother with the sword and stifled all compassion; his anger raged continually, and his fury flamed incessantly.","sources":{"KJV":{"text":"Thus saith the LORD; For three transgressions of Edom, and for four, I will not turn away the punishment thereof; because he did pursue his brother with the sword, and did cast off all pity, and his anger did tear perpetually, and he kept his wrath for ever:"},"BSB":{"text":"This is what the LORD says:  “For three transgressions of Edom, even four, I will not revoke My judgment, because he pursued his brother with the sword and stifled all compassion; his anger raged continually, and his fury flamed incessantly."}},"definableWords":["LORD","Edom","judgment","brother","anger"],"peopleInVerse":[]},"12":{"text":"But I will send a fire upon Teman, which shall devour the palaces of Bozrah.","ref":"Amos 1:12","synthesized":"So I will send fire upon Teman to consume the citadels of Bozrah.”","sources":{"KJV":{"text":"But I will send a fire upon Teman, which shall devour the palaces of Bozrah."},"BSB":{"text":"So I will send fire upon Teman to consume the citadels of Bozrah.”"}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"Thus saith the LORD; For three transgressions of the children of Ammon, and for four, I will not turn away the punishment thereof; because they have ripped up the women with child of Gilead, that they might enlarge their border:","ref":"Amos 1:13","synthesized":"This is what the LORD says:  “For three transgressions of the Ammonites, even four, I will not revoke My judgment, because they ripped open the pregnant women of Gilead in order to enlarge their territory.","sources":{"KJV":{"text":"Thus saith the LORD; For three transgressions of the children of Ammon, and for four, I will not turn away the punishment thereof; because they have ripped up the women with child of Gilead, that they might enlarge their border:"},"BSB":{"text":"This is what the LORD says:  “For three transgressions of the Ammonites, even four, I will not revoke My judgment, because they ripped open the pregnant women of Gilead in order to enlarge their territory."}},"definableWords":["LORD","judgment","women"],"peopleInVerse":["Ammonites"]},"14":{"text":"But I will kindle a fire in the wall of Rabbah, and it shall devour the palaces thereof, with shouting in the day of battle, with a tempest in the day of the whirlwind:","ref":"Amos 1:14","synthesized":"So I will kindle a fire in the walls of Rabbah to consume its citadels amid war cries on the day of battle and a violent wind on the day of tempest.","sources":{"KJV":{"text":"But I will kindle a fire in the wall of Rabbah, and it shall devour the palaces thereof, with shouting in the day of battle, with a tempest in the day of the whirlwind:"},"BSB":{"text":"So I will kindle a fire in the walls of Rabbah to consume its citadels amid war cries on the day of battle and a violent wind on the day of tempest."}},"definableWords":["day"],"peopleInVerse":[]},"15":{"text":"And their king shall go into captivity, he and his princes together, saith the LORD.","ref":"Amos 1:15","synthesized":"Their king will go into exile— he and his princes together,” says the LORD.","sources":{"KJV":{"text":"And their king shall go into captivity, he and his princes together, saith the LORD."},"BSB":{"text":"Their king will go into exile— he and his princes together,” says the LORD."}},"definableWords":["king","LORD"],"peopleInVerse":[]}}},"2":{"chapter":"2","title":"JUDGMENT ON JUDAH AND ISRAEL","verses":{"1":{"text":"Thus saith the LORD; For three transgressions of Moab, and for four, I will not turn away the punishment thereof; because he burned the bones of the king of Edom into lime:","ref":"Amos 2:1","synthesized":"This is what the LORD says:  “For three transgressions of Moab, even four, I will not revoke My judgment, because he burned to lime the bones of Edom’s king.","sources":{"KJV":{"text":"Thus saith the LORD; For three transgressions of Moab, and for four, I will not turn away the punishment thereof; because he burned the bones of the king of Edom into lime:"},"BSB":{"text":"This is what the LORD says:  “For three transgressions of Moab, even four, I will not revoke My judgment, because he burned to lime the bones of Edom’s king."}},"definableWords":["LORD","judgment","bones","Edom","king"],"peopleInVerse":[]},"2":{"text":"But I will send a fire upon Moab, and it shall devour the palaces of Kirioth: and Moab shall die with tumult, with shouting, and with the sound of the trumpet:","ref":"Amos 2:2","synthesized":"So I will send fire against Moab to consume the citadels of Kerioth. Moab will die in tumult, amid war cries and the sound of the ram’s horn.","sources":{"KJV":{"text":"But I will send a fire upon Moab, and it shall devour the palaces of Kirioth: and Moab shall die with tumult, with shouting, and with the sound of the trumpet:"},"BSB":{"text":"So I will send fire against Moab to consume the citadels of Kerioth. Moab will die in tumult, amid war cries and the sound of the ram’s horn."}},"definableWords":["die"],"peopleInVerse":[]},"3":{"text":"And I will cut off the judge from the midst thereof, and will slay all the princes thereof with him, saith the LORD.","ref":"Amos 2:3","synthesized":"I will cut off the ruler of Moab and kill all the officials with him,” says the LORD.","sources":{"KJV":{"text":"And I will cut off the judge from the midst thereof, and will slay all the princes thereof with him, saith the LORD."},"BSB":{"text":"I will cut off the ruler of Moab and kill all the officials with him,” says the LORD."}},"definableWords":["ruler","LORD"],"peopleInVerse":[]},"4":{"text":"Thus saith the LORD; For three transgressions of Judah, and for four, I will not turn away the punishment thereof; because they have despised the law of the LORD, and have not kept his commandments, and their lies caused them to err, after the which their fathers have walked:","ref":"Amos 2:4","synthesized":"This is what the LORD says:  “For three transgressions of Judah, even four, I will not revoke My judgment, because they reject the Law of the LORD and fail to keep His statutes; they are led astray by the lies in which their fathers walked.","sources":{"KJV":{"text":"Thus saith the LORD; For three transgressions of Judah, and for four, I will not turn away the punishment thereof; because they have despised the law of the LORD, and have not kept his commandments, and their lies caused them to err, after the which their fathers have walked:"},"BSB":{"text":"This is what the LORD says:  “For three transgressions of Judah, even four, I will not revoke My judgment, because they reject the Law of the LORD and fail to keep His statutes; they are led astray by the lies in which their fathers walked."}},"definableWords":["LORD","Judah","judgment","law","Lord","keep","fathers","walked"],"peopleInVerse":[]},"5":{"text":"But I will send a fire upon Judah, and it shall devour the palaces of Jerusalem.","ref":"Amos 2:5","synthesized":"So I will send fire upon Judah to consume the citadels of Jerusalem.”","sources":{"KJV":{"text":"But I will send a fire upon Judah, and it shall devour the palaces of Jerusalem."},"BSB":{"text":"So I will send fire upon Judah to consume the citadels of Jerusalem.”"}},"definableWords":["Judah","Jerusalem"],"peopleInVerse":[]},"6":{"text":"Thus saith the LORD; For three transgressions of Israel, and for four, I will not turn away the punishment thereof; because they sold the righteous for silver, and the poor for a pair of shoes;","ref":"Amos 2:6","synthesized":"This is what the LORD says:  “For three transgressions of Israel, even four, I will not revoke My judgment, because they sell the righteous for silver and the needy for a pair of sandals.","sources":{"KJV":{"text":"Thus saith the LORD; For three transgressions of Israel, and for four, I will not turn away the punishment thereof; because they sold the righteous for silver, and the poor for a pair of shoes;"},"BSB":{"text":"This is what the LORD says:  “For three transgressions of Israel, even four, I will not revoke My judgment, because they sell the righteous for silver and the needy for a pair of sandals."}},"definableWords":["LORD","Israel","judgment","righteous"],"peopleInVerse":[]},"7":{"text":"That pant after the dust of the earth on the head of the poor, and turn aside the way of the meek: and a man and his father will go in unto the same maid, to profane my holy name:","ref":"Amos 2:7","synthesized":"They trample on the heads of the poor as on the dust of the earth; they push the needy out of their way. A man and his father have relations with the same girl and so profane My holy name.","sources":{"KJV":{"text":"That pant after the dust of the earth on the head of the poor, and turn aside the way of the meek: and a man and his father will go in unto the same maid, to profane my holy name:"},"BSB":{"text":"They trample on the heads of the poor as on the dust of the earth; they push the needy out of their way. A man and his father have relations with the same girl and so profane My holy name."}},"definableWords":["earth","way","man","father","holy","name"],"peopleInVerse":[]},"8":{"text":"And they lay themselves down upon clothes laid to pledge by every altar, and they drink the wine of the condemned in the house of their god.","ref":"Amos 2:8","synthesized":"They lie down beside every altar on garments taken in pledge. And in the house of their God, they drink wine obtained through fines.","sources":{"KJV":{"text":"And they lay themselves down upon clothes laid to pledge by every altar, and they drink the wine of the condemned in the house of their god."},"BSB":{"text":"They lie down beside every altar on garments taken in pledge. And in the house of their God, they drink wine obtained through fines."}},"definableWords":["altar","house","God"],"peopleInVerse":[]},"9":{"text":"Yet destroyed I the Amorite before them, whose height was like the height of the cedars, and he was strong as the oaks; yet I destroyed his fruit from above, and his roots from beneath.","ref":"Amos 2:9","synthesized":"Yet it was I who destroyed the Amorite before them, though his height was like that of the cedars, and he was as strong as the oaks. Yet I destroyed his fruit above and his roots below.","sources":{"KJV":{"text":"Yet destroyed I the Amorite before them, whose height was like the height of the cedars, and he was strong as the oaks; yet I destroyed his fruit from above, and his roots from beneath."},"BSB":{"text":"Yet it was I who destroyed the Amorite before them, though his height was like that of the cedars, and he was as strong as the oaks. Yet I destroyed his fruit above and his roots below."}},"definableWords":["strong"],"peopleInVerse":[]},"10":{"text":"Also I brought you up from the land of Egypt, and led you forty years through the wilderness, to possess the land of the Amorite.","ref":"Amos 2:10","synthesized":"And I brought you up from the land of Egypt and led you forty years in the wilderness, that you might take possession of the land of the Amorite.","sources":{"KJV":{"text":"Also I brought you up from the land of Egypt, and led you forty years through the wilderness, to possess the land of the Amorite."},"BSB":{"text":"And I brought you up from the land of Egypt and led you forty years in the wilderness, that you might take possession of the land of the Amorite."}},"definableWords":["land","Egypt","years"],"peopleInVerse":[]},"11":{"text":"And I raised up of your sons for prophets, and of your young men for Nazarites. Is it not even thus, O ye children of Israel? saith the LORD.","ref":"Amos 2:11","synthesized":"I raised up prophets from your sons and Nazirites from your young men. Is this not true, O children of Israel?” declares the LORD.","sources":{"KJV":{"text":"And I raised up of your sons for prophets, and of your young men for Nazarites. Is it not even thus, O ye children of Israel? saith the LORD."},"BSB":{"text":"I raised up prophets from your sons and Nazirites from your young men. Is this not true, O children of Israel?” declares the LORD."}},"definableWords":["sons","men","Israel","LORD"],"peopleInVerse":[]},"12":{"text":"But ye gave the Nazarites wine to drink; and commanded the prophets, saying, Prophesy not.","ref":"Amos 2:12","synthesized":"“But you made the Nazirites drink wine and commanded the prophets not to prophesy.","sources":{"KJV":{"text":"But ye gave the Nazarites wine to drink; and commanded the prophets, saying, Prophesy not."},"BSB":{"text":"“But you made the Nazirites drink wine and commanded the prophets not to prophesy."}},"definableWords":["made"],"peopleInVerse":[]},"13":{"text":"Behold, I am pressed under you, as a cart is pressed that is full of sheaves.","ref":"Amos 2:13","synthesized":"Behold, I am about to crush you in your place as with a cart full of grain.","sources":{"KJV":{"text":"Behold, I am pressed under you, as a cart is pressed that is full of sheaves."},"BSB":{"text":"Behold, I am about to crush you in your place as with a cart full of grain."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"Therefore the flight shall perish from the swift, and the strong shall not strengthen his force, neither shall the mighty deliver himself:","ref":"Amos 2:14","synthesized":"Escape will fail the swift, the strong will not prevail by his strength, and the mighty will not save his life.","sources":{"KJV":{"text":"Therefore the flight shall perish from the swift, and the strong shall not strengthen his force, neither shall the mighty deliver himself:"},"BSB":{"text":"Escape will fail the swift, the strong will not prevail by his strength, and the mighty will not save his life."}},"definableWords":["strong","mighty","life"],"peopleInVerse":[]},"15":{"text":"Neither shall he stand that handleth the bow; and he that is swift of foot shall not deliver himself: neither shall he that rideth the horse deliver himself.","ref":"Amos 2:15","synthesized":"The archer will not stand his ground, the fleet of foot will not escape, and the horseman will not save his life.","sources":{"KJV":{"text":"Neither shall he stand that handleth the bow; and he that is swift of foot shall not deliver himself: neither shall he that rideth the horse deliver himself."},"BSB":{"text":"The archer will not stand his ground, the fleet of foot will not escape, and the horseman will not save his life."}},"definableWords":["stand","ground","life"],"peopleInVerse":[]},"16":{"text":"And he that is courageous among the mighty shall flee away naked in that day, saith the LORD.","ref":"Amos 2:16","synthesized":"Even the bravest of mighty men will flee naked on that day,” declares the LORD.","sources":{"KJV":{"text":"And he that is courageous among the mighty shall flee away naked in that day, saith the LORD."},"BSB":{"text":"Even the bravest of mighty men will flee naked on that day,” declares the LORD."}},"definableWords":["mighty","men","naked","day","LORD"],"peopleInVerse":[]}}},"3":{"chapter":"3","title":"CAN TWO WALK TOGETHER?","verses":{"1":{"text":"Hear this word that the LORD hath spoken against you, O children of Israel, against the whole family which I brought up from the land of Egypt, saying,","ref":"Amos 3:1","synthesized":"Hear this word that the LORD has spoken against you, O children of Israel, against the whole family that I brought up out of the land of Egypt:","sources":{"KJV":{"text":"Hear this word that the LORD hath spoken against you, O children of Israel, against the whole family which I brought up from the land of Egypt, saying,"},"BSB":{"text":"Hear this word that the LORD has spoken against you, O children of Israel, against the whole family that I brought up out of the land of Egypt:"}},"definableWords":["hear","word","LORD","Israel","family","land","Egypt"],"peopleInVerse":[]},"2":{"text":"You only have I known of all the families of the earth: therefore I will punish you for all your iniquities.","ref":"Amos 3:2","synthesized":"“Only you have I known from all the families of the earth; therefore I will punish you for all your iniquities.”","sources":{"KJV":{"text":"You only have I known of all the families of the earth: therefore I will punish you for all your iniquities."},"BSB":{"text":"“Only you have I known from all the families of the earth; therefore I will punish you for all your iniquities.”"}},"definableWords":["families","earth"],"peopleInVerse":[]},"3":{"text":"Can two walk together, except they be agreed?","ref":"Amos 3:3","synthesized":"Can two walk together without agreeing where to go?","sources":{"KJV":{"text":"Can two walk together, except they be agreed?"},"BSB":{"text":"Can two walk together without agreeing where to go?"}},"definableWords":["walk"],"peopleInVerse":[]},"4":{"text":"Will a lion roar in the forest, when he hath no prey? will a young lion cry out of his den, if he have taken nothing?","ref":"Amos 3:4","synthesized":"Does a lion roar in the forest when he has no prey? Does a young lion growl in his den if he has caught nothing?","sources":{"KJV":{"text":"Will a lion roar in the forest, when he hath no prey? will a young lion cry out of his den, if he have taken nothing?"},"BSB":{"text":"Does a lion roar in the forest when he has no prey? Does a young lion growl in his den if he has caught nothing?"}},"definableWords":["lion"],"peopleInVerse":[]},"5":{"text":"Can a bird fall in a snare upon the earth, where no gin is for him? shall one take up a snare from the earth, and have taken nothing at all?","ref":"Amos 3:5","synthesized":"Does a bird land in a snare where no bait has been set? Does a trap spring from the ground when it has nothing to catch?","sources":{"KJV":{"text":"Can a bird fall in a snare upon the earth, where no gin is for him? shall one take up a snare from the earth, and have taken nothing at all?"},"BSB":{"text":"Does a bird land in a snare where no bait has been set? Does a trap spring from the ground when it has nothing to catch?"}},"definableWords":["bird","land","ground"],"peopleInVerse":[]},"6":{"text":"Shall a trumpet be blown in the city, and the people not be afraid? shall there be evil in a city, and the LORD hath not done it?","ref":"Amos 3:6","synthesized":"If a ram’s horn sounds in a city, do the people not tremble? If calamity comes to a city, has not the LORD caused it?","sources":{"KJV":{"text":"Shall a trumpet be blown in the city, and the people not be afraid? shall there be evil in a city, and the LORD hath not done it?"},"BSB":{"text":"If a ram’s horn sounds in a city, do the people not tremble? If calamity comes to a city, has not the LORD caused it?"}},"definableWords":["people","LORD"],"peopleInVerse":[]},"7":{"text":"Surely the Lord GOD will do nothing, but he revealeth his secret unto his servants the prophets.","ref":"Amos 3:7","synthesized":"Surely the Lord GOD does nothing without revealing His plan to His servants the prophets.","sources":{"KJV":{"text":"Surely the Lord GOD will do nothing, but he revealeth his secret unto his servants the prophets."},"BSB":{"text":"Surely the Lord GOD does nothing without revealing His plan to His servants the prophets."}},"definableWords":["Lord","God","servants"],"peopleInVerse":[]},"8":{"text":"The lion hath roared, who will not fear? the Lord GOD hath spoken, who can but prophesy?","ref":"Amos 3:8","synthesized":"The lion has roared— who will not fear? The Lord GOD has spoken— who will not prophesy?","sources":{"KJV":{"text":"The lion hath roared, who will not fear? the Lord GOD hath spoken, who can but prophesy?"},"BSB":{"text":"The lion has roared— who will not fear? The Lord GOD has spoken— who will not prophesy?"}},"definableWords":["lion","fear","Lord","God"],"peopleInVerse":[]},"9":{"text":"Publish in the palaces at Ashdod, and in the palaces in the land of Egypt, and say, Assemble yourselves upon the mountains of Samaria, and behold the great tumults in the midst thereof, and the oppressed in the midst thereof.","ref":"Amos 3:9","synthesized":"Proclaim to the citadels of Ashdod and to the citadels of Egypt: “Assemble on the mountains of Samaria; see the great unrest in the city and the acts of oppression in her midst.”","sources":{"KJV":{"text":"Publish in the palaces at Ashdod, and in the palaces in the land of Egypt, and say, Assemble yourselves upon the mountains of Samaria, and behold the great tumults in the midst thereof, and the oppressed in the midst thereof."},"BSB":{"text":"Proclaim to the citadels of Ashdod and to the citadels of Egypt: “Assemble on the mountains of Samaria; see the great unrest in the city and the acts of oppression in her midst.”"}},"definableWords":["Egypt","Samaria","see","great"],"peopleInVerse":[]},"10":{"text":"For they know not to do right, saith the LORD, who store up violence and robbery in their palaces.","ref":"Amos 3:10","synthesized":"“For they know not how to do right,” declares the LORD. “They store up violence and destruction in their citadels.”","sources":{"KJV":{"text":"For they know not to do right, saith the LORD, who store up violence and robbery in their palaces."},"BSB":{"text":"“For they know not how to do right,” declares the LORD. “They store up violence and destruction in their citadels.”"}},"definableWords":["LORD"],"peopleInVerse":[]},"11":{"text":"Therefore thus saith the Lord GOD; An adversary there shall be even round about the land; and he shall bring down thy strength from thee, and thy palaces shall be spoiled.","ref":"Amos 3:11","synthesized":"Therefore this is what the Lord GOD says:  “An enemy will surround the land; he will pull down your strongholds and plunder your citadels.”","sources":{"KJV":{"text":"Therefore thus saith the Lord GOD; An adversary there shall be even round about the land; and he shall bring down thy strength from thee, and thy palaces shall be spoiled."},"BSB":{"text":"Therefore this is what the Lord GOD says:  “An enemy will surround the land; he will pull down your strongholds and plunder your citadels.”"}},"definableWords":["Lord","God","land"],"peopleInVerse":[]},"12":{"text":"Thus saith the LORD; As the shepherd taketh out of the mouth of the lion two legs, or a piece of an ear; so shall the children of Israel be taken out that dwell in Samaria in the corner of a bed, and in Damascus in a couch.","ref":"Amos 3:12","synthesized":"This is what the LORD says:  “As the shepherd snatches from the mouth of the lion two legs or a piece of an ear, so the Israelites dwelling in Samaria will be rescued having just the corner of a bed or the cushion of a couch.","sources":{"KJV":{"text":"Thus saith the LORD; As the shepherd taketh out of the mouth of the lion two legs, or a piece of an ear; so shall the children of Israel be taken out that dwell in Samaria in the corner of a bed, and in Damascus in a couch."},"BSB":{"text":"This is what the LORD says:  “As the shepherd snatches from the mouth of the lion two legs or a piece of an ear, so the Israelites dwelling in Samaria will be rescued having just the corner of a bed or the cushion of a couch."}},"definableWords":["LORD","shepherd","lion","or","Israelites","Samaria"],"peopleInVerse":[]},"13":{"text":"Hear ye, and testify in the house of Jacob, saith the Lord GOD, the God of hosts,","ref":"Amos 3:13","synthesized":"Hear and testify against the house of Jacob, declares the Lord GOD, the God of Hosts.","sources":{"KJV":{"text":"Hear ye, and testify in the house of Jacob, saith the Lord GOD, the God of hosts,"},"BSB":{"text":"Hear and testify against the house of Jacob, declares the Lord GOD, the God of Hosts."}},"definableWords":["hear","house","Jacob","Lord","God"],"peopleInVerse":["Jacob"]},"14":{"text":"That in the day that I shall visit the transgressions of Israel upon him I will also visit the altars of Bethel: and the horns of the altar shall be cut off, and fall to the ground.","ref":"Amos 3:14","synthesized":"On the day I punish Israel for their transgressions, I will visit destruction on the altars of Bethel; the horns of the altar will be cut off, and they will fall to the ground.","sources":{"KJV":{"text":"That in the day that I shall visit the transgressions of Israel upon him I will also visit the altars of Bethel: and the horns of the altar shall be cut off, and fall to the ground."},"BSB":{"text":"On the day I punish Israel for their transgressions, I will visit destruction on the altars of Bethel; the horns of the altar will be cut off, and they will fall to the ground."}},"definableWords":["day","Israel","Bethel","altar","ground"],"peopleInVerse":[]},"15":{"text":"And I will smite the winter house with the summer house; and the houses of ivory shall perish, and the great houses shall have an end, saith the LORD.","ref":"Amos 3:15","synthesized":"I will tear down the winter house along with the summer house; the houses of ivory will also perish, and the great houses will come to an end,” declares the LORD.","sources":{"KJV":{"text":"And I will smite the winter house with the summer house; and the houses of ivory shall perish, and the great houses shall have an end, saith the LORD."},"BSB":{"text":"I will tear down the winter house along with the summer house; the houses of ivory will also perish, and the great houses will come to an end,” declares the LORD."}},"definableWords":["house","great","LORD"],"peopleInVerse":[]}}},"4":{"chapter":"4","title":"PREPARE TO MEET THY GOD","verses":{"1":{"text":"Hear this word, ye kine of Bashan, that are in the mountain of Samaria, which oppress the poor, which crush the needy, which say to their masters, Bring, and let us drink.","ref":"Amos 4:1","synthesized":"Hear this word, you cows of Bashan on Mount Samaria, you women who oppress the poor and crush the needy, who say to your husbands, “Bring us more to drink.”","sources":{"KJV":{"text":"Hear this word, ye kine of Bashan, that are in the mountain of Samaria, which oppress the poor, which crush the needy, which say to their masters, Bring, and let us drink."},"BSB":{"text":"Hear this word, you cows of Bashan on Mount Samaria, you women who oppress the poor and crush the needy, who say to your husbands, “Bring us more to drink.”"}},"definableWords":["hear","word","Samaria","women"],"peopleInVerse":[]},"2":{"text":"The Lord GOD hath sworn by his holiness, that, lo, the days shall come upon you, that he will take you away with hooks, and your posterity with fishhooks.","ref":"Amos 4:2","synthesized":"The Lord GOD has sworn by His holiness:  “Behold, the days are coming when you will be taken away with hooks, and your posterity with fishhooks.","sources":{"KJV":{"text":"The Lord GOD hath sworn by his holiness, that, lo, the days shall come upon you, that he will take you away with hooks, and your posterity with fishhooks."},"BSB":{"text":"The Lord GOD has sworn by His holiness:  “Behold, the days are coming when you will be taken away with hooks, and your posterity with fishhooks."}},"definableWords":["Lord","God","days"],"peopleInVerse":[]},"3":{"text":"And ye shall go out at the breaches, every cow at that which is before her; and ye shall cast them into the palace, saith the LORD.","ref":"Amos 4:3","synthesized":"You will go out through broken walls, each one straight ahead of her, and you will be cast out toward Harmon,” declares the LORD.","sources":{"KJV":{"text":"And ye shall go out at the breaches, every cow at that which is before her; and ye shall cast them into the palace, saith the LORD."},"BSB":{"text":"You will go out through broken walls, each one straight ahead of her, and you will be cast out toward Harmon,” declares the LORD."}},"definableWords":["one","LORD"],"peopleInVerse":[]},"4":{"text":"Come to Bethel, and transgress; at Gilgal multiply transgression; and bring your sacrifices every morning, and your tithes after three years:","ref":"Amos 4:4","synthesized":"“Go to Bethel and transgress; rebel even more at Gilgal! Bring your sacrifices every morning, your tithes every three days.","sources":{"KJV":{"text":"Come to Bethel, and transgress; at Gilgal multiply transgression; and bring your sacrifices every morning, and your tithes after three years:"},"BSB":{"text":"“Go to Bethel and transgress; rebel even more at Gilgal! Bring your sacrifices every morning, your tithes every three days."}},"definableWords":["Bethel","days"],"peopleInVerse":[]},"5":{"text":"And offer a sacrifice of thanksgiving with leaven, and proclaim and publish the free offerings: for this liketh you, O ye children of Israel, saith the Lord GOD.","ref":"Amos 4:5","synthesized":"Offer leavened bread as a thank offering, and loudly proclaim your freewill offerings. For that is what you children of Israel love to do,” declares the Lord GOD.","sources":{"KJV":{"text":"And offer a sacrifice of thanksgiving with leaven, and proclaim and publish the free offerings: for this liketh you, O ye children of Israel, saith the Lord GOD."},"BSB":{"text":"Offer leavened bread as a thank offering, and loudly proclaim your freewill offerings. For that is what you children of Israel love to do,” declares the Lord GOD."}},"definableWords":["offering","Israel","love","Lord","God"],"peopleInVerse":[]},"6":{"text":"And I also have given you cleanness of teeth in all your cities, and want of bread in all your places: yet have ye not returned unto me, saith the LORD.","ref":"Amos 4:6","synthesized":"“I beset all your cities with cleanness of teeth and all your towns with lack of bread, yet you did not return to Me,” declares the LORD.","sources":{"KJV":{"text":"And I also have given you cleanness of teeth in all your cities, and want of bread in all your places: yet have ye not returned unto me, saith the LORD."},"BSB":{"text":"“I beset all your cities with cleanness of teeth and all your towns with lack of bread, yet you did not return to Me,” declares the LORD."}},"definableWords":["LORD"],"peopleInVerse":[]},"7":{"text":"And also I have withholden the rain from you, when there were yet three months to the harvest: and I caused it to rain upon one city, and caused it not to rain upon another city: one piece was rained upon, and the piece whereupon it rained not withered.","ref":"Amos 4:7","synthesized":"“I also withheld the rain from you when the harvest was three months away. I sent rain on one city but withheld it from another. One field received rain; another without rain withered.","sources":{"KJV":{"text":"And also I have withholden the rain from you, when there were yet three months to the harvest: and I caused it to rain upon one city, and caused it not to rain upon another city: one piece was rained upon, and the piece whereupon it rained not withered."},"BSB":{"text":"“I also withheld the rain from you when the harvest was three months away. I sent rain on one city but withheld it from another. One field received rain; another without rain withered."}},"definableWords":["one","field"],"peopleInVerse":[]},"8":{"text":"So two or three cities wandered unto one city, to drink water; but they were not satisfied: yet have ye not returned unto me, saith the LORD.","ref":"Amos 4:8","synthesized":"People staggered from city to city for water to drink, but they were not satisfied; yet you did not return to Me,” declares the LORD.","sources":{"KJV":{"text":"So two or three cities wandered unto one city, to drink water; but they were not satisfied: yet have ye not returned unto me, saith the LORD."},"BSB":{"text":"People staggered from city to city for water to drink, but they were not satisfied; yet you did not return to Me,” declares the LORD."}},"definableWords":["people","water","LORD"],"peopleInVerse":[]},"9":{"text":"I have smitten you with blasting and mildew: when your gardens and your vineyards and your fig trees and your olive trees increased, the palmerworm devoured them: yet have ye not returned unto me, saith the LORD.","ref":"Amos 4:9","synthesized":"“I struck you with blight and mildew in your growing gardens and vineyards; the locust devoured your fig and olive trees, yet you did not return to Me,” declares the LORD.","sources":{"KJV":{"text":"I have smitten you with blasting and mildew: when your gardens and your vineyards and your fig trees and your olive trees increased, the palmerworm devoured them: yet have ye not returned unto me, saith the LORD."},"BSB":{"text":"“I struck you with blight and mildew in your growing gardens and vineyards; the locust devoured your fig and olive trees, yet you did not return to Me,” declares the LORD."}},"definableWords":["trees","LORD"],"peopleInVerse":[]},"10":{"text":"I have sent among you the pestilence after the manner of Egypt: your young men have I slain with the sword, and have taken away your horses; and I have made the stink of your camps to come up unto your nostrils: yet have ye not returned unto me, saith the LORD.","ref":"Amos 4:10","synthesized":"“I sent plagues among you like those of Egypt; I killed your young men with the sword, along with your captured horses. I filled your nostrils with the stench of your camp, yet you did not return to Me,” declares the LORD.","sources":{"KJV":{"text":"I have sent among you the pestilence after the manner of Egypt: your young men have I slain with the sword, and have taken away your horses; and I have made the stink of your camps to come up unto your nostrils: yet have ye not returned unto me, saith the LORD."},"BSB":{"text":"“I sent plagues among you like those of Egypt; I killed your young men with the sword, along with your captured horses. I filled your nostrils with the stench of your camp, yet you did not return to Me,” declares the LORD."}},"definableWords":["Egypt","men","LORD"],"peopleInVerse":[]},"11":{"text":"I have overthrown some of you, as God overthrew Sodom and Gomorrah, and ye were as a firebrand plucked out of the burning: yet have ye not returned unto me, saith the LORD.","ref":"Amos 4:11","synthesized":"“Some of you I overthrew as I overthrew Sodom and Gomorrah, and you were like a firebrand snatched from a blaze, yet you did not return to Me,” declares the LORD.","sources":{"KJV":{"text":"I have overthrown some of you, as God overthrew Sodom and Gomorrah, and ye were as a firebrand plucked out of the burning: yet have ye not returned unto me, saith the LORD."},"BSB":{"text":"“Some of you I overthrew as I overthrew Sodom and Gomorrah, and you were like a firebrand snatched from a blaze, yet you did not return to Me,” declares the LORD."}},"definableWords":["Sodom","Gomorrah","LORD"],"peopleInVerse":[]},"12":{"text":"Therefore thus will I do unto thee, O Israel: and because I will do this unto thee, prepare to meet thy God, O Israel.","ref":"Amos 4:12","synthesized":"“Therefore, that is what I will do to you, O Israel, and since I will do this to you, prepare to meet your God, O Israel!","sources":{"KJV":{"text":"Therefore thus will I do unto thee, O Israel: and because I will do this unto thee, prepare to meet thy God, O Israel."},"BSB":{"text":"“Therefore, that is what I will do to you, O Israel, and since I will do this to you, prepare to meet your God, O Israel!"}},"definableWords":["Israel","God"],"peopleInVerse":[]},"13":{"text":"For, lo, he that formeth the mountains, and createth the wind, and declareth unto man what is his thought, that maketh the morning darkness, and treadeth upon the high places of the earth, The LORD, The God of hosts, is his name.","ref":"Amos 4:13","synthesized":"For behold, He who forms the mountains, who creates the wind and reveals His thoughts to man, who turns the dawn to darkness and strides on the heights of the earth— the LORD, the God of Hosts, is His name.”","sources":{"KJV":{"text":"For, lo, he that formeth the mountains, and createth the wind, and declareth unto man what is his thought, that maketh the morning darkness, and treadeth upon the high places of the earth, The LORD, The God of hosts, is his name."},"BSB":{"text":"For behold, He who forms the mountains, who creates the wind and reveals His thoughts to man, who turns the dawn to darkness and strides on the heights of the earth— the LORD, the God of Hosts, is His name.”"}},"definableWords":["man","darkness","earth","LORD","God","name"],"peopleInVerse":[]}}},"5":{"chapter":"5","title":"LET JUSTICE ROLL DOWN","verses":{"1":{"text":"Hear ye this word which I take up against you, even a lamentation, O house of Israel.","ref":"Amos 5:1","synthesized":"Hear this word, O house of Israel, this lamentation I take up against you:","sources":{"KJV":{"text":"Hear ye this word which I take up against you, even a lamentation, O house of Israel."},"BSB":{"text":"Hear this word, O house of Israel, this lamentation I take up against you:"}},"definableWords":["hear","word","house","Israel"],"peopleInVerse":[]},"2":{"text":"The virgin of Israel is fallen; she shall no more rise: she is forsaken upon her land; there is none to raise her up.","ref":"Amos 5:2","synthesized":"“Fallen is Virgin Israel, never to rise again. She lies abandoned on her land, with no one to raise her up.”","sources":{"KJV":{"text":"The virgin of Israel is fallen; she shall no more rise: she is forsaken upon her land; there is none to raise her up."},"BSB":{"text":"“Fallen is Virgin Israel, never to rise again. She lies abandoned on her land, with no one to raise her up.”"}},"definableWords":["Israel","land","one"],"peopleInVerse":[]},"3":{"text":"For thus saith the Lord GOD; The city that went out by a thousand shall leave an hundred, and that which went forth by an hundred shall leave ten, to the house of Israel.","ref":"Amos 5:3","synthesized":"This is what the Lord GOD says:  “The city that marches out a thousand strong will only see a hundred return, and the one that marches out a hundred strong will have but ten left in the house of Israel.”","sources":{"KJV":{"text":"For thus saith the Lord GOD; The city that went out by a thousand shall leave an hundred, and that which went forth by an hundred shall leave ten, to the house of Israel."},"BSB":{"text":"This is what the Lord GOD says:  “The city that marches out a thousand strong will only see a hundred return, and the one that marches out a hundred strong will have but ten left in the house of Israel.”"}},"definableWords":["Lord","God","strong","see","one","house","Israel"],"peopleInVerse":[]},"4":{"text":"For thus saith the LORD unto the house of Israel, Seek ye me, and ye shall live:","ref":"Amos 5:4","synthesized":"For this is what the LORD says to the house of Israel:  “Seek Me and live!","sources":{"KJV":{"text":"For thus saith the LORD unto the house of Israel, Seek ye me, and ye shall live:"},"BSB":{"text":"For this is what the LORD says to the house of Israel:  “Seek Me and live!"}},"definableWords":["LORD","house","Israel","seek","live"],"peopleInVerse":[]},"5":{"text":"But seek not Bethel, nor enter into Gilgal, and pass not to Beersheba: for Gilgal shall surely go into captivity, and Bethel shall come to nought.","ref":"Amos 5:5","synthesized":"Do not seek Bethel or go to Gilgal; do not journey to Beersheba, for Gilgal will surely go into exile, and Bethel will come to nothing.","sources":{"KJV":{"text":"But seek not Bethel, nor enter into Gilgal, and pass not to Beersheba: for Gilgal shall surely go into captivity, and Bethel shall come to nought."},"BSB":{"text":"Do not seek Bethel or go to Gilgal; do not journey to Beersheba, for Gilgal will surely go into exile, and Bethel will come to nothing."}},"definableWords":["seek","Bethel","or","Beersheba"],"peopleInVerse":[]},"6":{"text":"Seek the LORD, and ye shall live; lest he break out like fire in the house of Joseph, and devour it, and there be none to quench it in Bethel.","ref":"Amos 5:6","synthesized":"Seek the LORD and live, or He will sweep like fire through the house of Joseph; it will devour everything, with no one at Bethel to extinguish it.","sources":{"KJV":{"text":"Seek the LORD, and ye shall live; lest he break out like fire in the house of Joseph, and devour it, and there be none to quench it in Bethel."},"BSB":{"text":"Seek the LORD and live, or He will sweep like fire through the house of Joseph; it will devour everything, with no one at Bethel to extinguish it."}},"definableWords":["seek","LORD","live","or","house","Joseph","one","Bethel"],"peopleInVerse":["Joseph"]},"7":{"text":"Ye who turn judgment to wormwood, and leave off righteousness in the earth,","ref":"Amos 5:7","synthesized":"There are those who turn justice into wormwood and cast righteousness to the ground.","sources":{"KJV":{"text":"Ye who turn judgment to wormwood, and leave off righteousness in the earth,"},"BSB":{"text":"There are those who turn justice into wormwood and cast righteousness to the ground."}},"definableWords":["justice","righteousness","ground"],"peopleInVerse":[]},"8":{"text":"Seek him that maketh the seven stars and Orion, and turneth the shadow of death into the morning, and maketh the day dark with night: that calleth for the waters of the sea, and poureth them out upon the face of the earth: The LORD is his name:","ref":"Amos 5:8","synthesized":"He who made the Pleiades and Orion, who turns darkness into dawn and darkens day into night, who summons the waters of the sea and pours them over the face of the earth— the LORD is His name—","sources":{"KJV":{"text":"Seek him that maketh the seven stars and Orion, and turneth the shadow of death into the morning, and maketh the day dark with night: that calleth for the waters of the sea, and poureth them out upon the face of the earth: The LORD is his name:"},"BSB":{"text":"He who made the Pleiades and Orion, who turns darkness into dawn and darkens day into night, who summons the waters of the sea and pours them over the face of the earth— the LORD is His name—"}},"definableWords":["made","darkness","day","night","waters","sea","earth","LORD","name"],"peopleInVerse":[]},"9":{"text":"That strengtheneth the spoiled against the strong, so that the spoiled shall come against the fortress.","ref":"Amos 5:9","synthesized":"He flashes destruction on the strong, so that fury comes upon the stronghold.","sources":{"KJV":{"text":"That strengtheneth the spoiled against the strong, so that the spoiled shall come against the fortress."},"BSB":{"text":"He flashes destruction on the strong, so that fury comes upon the stronghold."}},"definableWords":["strong"],"peopleInVerse":[]},"10":{"text":"They hate him that rebuketh in the gate, and they abhor him that speaketh uprightly.","ref":"Amos 5:10","synthesized":"There are those who hate the one who reproves in the gate and despise him who speaks with integrity.","sources":{"KJV":{"text":"They hate him that rebuketh in the gate, and they abhor him that speaketh uprightly."},"BSB":{"text":"There are those who hate the one who reproves in the gate and despise him who speaks with integrity."}},"definableWords":["one"],"peopleInVerse":[]},"11":{"text":"Forasmuch therefore as your treading is upon the poor, and ye take from him burdens of wheat: ye have built houses of hewn stone, but ye shall not dwell in them; ye have planted pleasant vineyards, but ye shall not drink wine of them.","ref":"Amos 5:11","synthesized":"Therefore, because you trample on the poor and exact from him a tax of grain, you will never live in the stone houses you have built; you will never drink the wine from the lush vineyards you have planted.","sources":{"KJV":{"text":"Forasmuch therefore as your treading is upon the poor, and ye take from him burdens of wheat: ye have built houses of hewn stone, but ye shall not dwell in them; ye have planted pleasant vineyards, but ye shall not drink wine of them."},"BSB":{"text":"Therefore, because you trample on the poor and exact from him a tax of grain, you will never live in the stone houses you have built; you will never drink the wine from the lush vineyards you have planted."}},"definableWords":["live","stone"],"peopleInVerse":[]},"12":{"text":"For I know your manifold transgressions and your mighty sins: they afflict the just, they take a bribe, and they turn aside the poor in the gate from their right.","ref":"Amos 5:12","synthesized":"For I know that your transgressions are many and your sins are numerous. You oppress the righteous by taking bribes; you deprive the poor of justice in the gate.","sources":{"KJV":{"text":"For I know your manifold transgressions and your mighty sins: they afflict the just, they take a bribe, and they turn aside the poor in the gate from their right."},"BSB":{"text":"For I know that your transgressions are many and your sins are numerous. You oppress the righteous by taking bribes; you deprive the poor of justice in the gate."}},"definableWords":["righteous","justice"],"peopleInVerse":[]},"13":{"text":"Therefore the prudent shall keep silence in that time; for it is an evil time.","ref":"Amos 5:13","synthesized":"Therefore, the prudent keep silent in such times, for the days are evil.","sources":{"KJV":{"text":"Therefore the prudent shall keep silence in that time; for it is an evil time."},"BSB":{"text":"Therefore, the prudent keep silent in such times, for the days are evil."}},"definableWords":["keep","days","evil"],"peopleInVerse":[]},"14":{"text":"Seek good, and not evil, that ye may live: and so the LORD, the God of hosts, shall be with you, as ye have spoken.","ref":"Amos 5:14","synthesized":"Seek good, not evil, so that you may live. And the LORD, the God of Hosts, will be with you, as you have claimed.","sources":{"KJV":{"text":"Seek good, and not evil, that ye may live: and so the LORD, the God of hosts, shall be with you, as ye have spoken."},"BSB":{"text":"Seek good, not evil, so that you may live. And the LORD, the God of Hosts, will be with you, as you have claimed."}},"definableWords":["seek","good","evil","live","LORD","God"],"peopleInVerse":[]},"15":{"text":"Hate the evil, and love the good, and establish judgment in the gate: it may be that the LORD God of hosts will be gracious unto the remnant of Joseph.","ref":"Amos 5:15","synthesized":"Hate evil and love good; establish justice in the gate. Perhaps the LORD, the God of Hosts, will be gracious to the remnant of Joseph.”","sources":{"KJV":{"text":"Hate the evil, and love the good, and establish judgment in the gate: it may be that the LORD God of hosts will be gracious unto the remnant of Joseph."},"BSB":{"text":"Hate evil and love good; establish justice in the gate. Perhaps the LORD, the God of Hosts, will be gracious to the remnant of Joseph.”"}},"definableWords":["evil","love","good","justice","LORD","God","remnant","Joseph"],"peopleInVerse":["Joseph"]},"16":{"text":"Therefore the LORD, the God of hosts, the LORD, saith thus; Wailing shall be in all streets; and they shall say in all the highways, Alas! alas! and they shall call the husbandman to mourning, and such as are skilful of lamentation to wailing.","ref":"Amos 5:16","synthesized":"Therefore this is what the LORD, the God of Hosts, the Lord, says:  “There will be wailing in all the public squares and cries of ‘Alas! Alas!’ in all the streets. The farmer will be summoned to mourn, and the mourners to wail.","sources":{"KJV":{"text":"Therefore the LORD, the God of hosts, the LORD, saith thus; Wailing shall be in all streets; and they shall say in all the highways, Alas! alas! and they shall call the husbandman to mourning, and such as are skilful of lamentation to wailing."},"BSB":{"text":"Therefore this is what the LORD, the God of Hosts, the Lord, says:  “There will be wailing in all the public squares and cries of ‘Alas! Alas!’ in all the streets. The farmer will be summoned to mourn, and the mourners to wail."}},"definableWords":["LORD","God","Lord"],"peopleInVerse":[]},"17":{"text":"And in all vineyards shall be wailing: for I will pass through thee, saith the LORD.","ref":"Amos 5:17","synthesized":"There will be wailing in all the vineyards, for I will pass through your midst,” says the LORD.","sources":{"KJV":{"text":"And in all vineyards shall be wailing: for I will pass through thee, saith the LORD."},"BSB":{"text":"There will be wailing in all the vineyards, for I will pass through your midst,” says the LORD."}},"definableWords":["LORD"],"peopleInVerse":[]},"18":{"text":"Woe unto you that desire the day of the LORD! to what end is it for you? the day of the LORD is darkness, and not light.","ref":"Amos 5:18","synthesized":"Woe to you who long for the Day of the LORD! What will the Day of the LORD be for you? It will be darkness and not light.","sources":{"KJV":{"text":"Woe unto you that desire the day of the LORD! to what end is it for you? the day of the LORD is darkness, and not light."},"BSB":{"text":"Woe to you who long for the Day of the LORD! What will the Day of the LORD be for you? It will be darkness and not light."}},"definableWords":["day","LORD","Lord","darkness","light"],"peopleInVerse":[]},"19":{"text":"As if a man did flee from a lion, and a bear met him; or went into the house, and leaned his hand on the wall, and a serpent bit him.","ref":"Amos 5:19","synthesized":"It will be like a man who flees from a lion, only to encounter a bear, or who enters his house and rests his hand against the wall, only to be bitten by a snake.","sources":{"KJV":{"text":"As if a man did flee from a lion, and a bear met him; or went into the house, and leaned his hand on the wall, and a serpent bit him."},"BSB":{"text":"It will be like a man who flees from a lion, only to encounter a bear, or who enters his house and rests his hand against the wall, only to be bitten by a snake."}},"definableWords":["man","lion","or","house"],"peopleInVerse":[]},"20":{"text":"Shall not the day of the LORD be darkness, and not light? even very dark, and no brightness in it?","ref":"Amos 5:20","synthesized":"Will not the Day of the LORD be darkness and not light, even gloom with no brightness in it?","sources":{"KJV":{"text":"Shall not the day of the LORD be darkness, and not light? even very dark, and no brightness in it?"},"BSB":{"text":"Will not the Day of the LORD be darkness and not light, even gloom with no brightness in it?"}},"definableWords":["day","LORD","darkness","light"],"peopleInVerse":[]},"21":{"text":"I hate, I despise your feast days, and I will not smell in your solemn assemblies.","ref":"Amos 5:21","synthesized":"“I hate, I despise your feasts! I cannot stand the stench of your solemn assemblies.","sources":{"KJV":{"text":"I hate, I despise your feast days, and I will not smell in your solemn assemblies."},"BSB":{"text":"“I hate, I despise your feasts! I cannot stand the stench of your solemn assemblies."}},"definableWords":["stand"],"peopleInVerse":[]},"22":{"text":"Though ye offer me burnt offerings and your meat offerings, I will not accept them: neither will I regard the peace offerings of your fat beasts.","ref":"Amos 5:22","synthesized":"Even though you offer Me burnt offerings and grain offerings, I will not accept them; for your peace offerings of fattened cattle I will have no regard.","sources":{"KJV":{"text":"Though ye offer me burnt offerings and your meat offerings, I will not accept them: neither will I regard the peace offerings of your fat beasts."},"BSB":{"text":"Even though you offer Me burnt offerings and grain offerings, I will not accept them; for your peace offerings of fattened cattle I will have no regard."}},"definableWords":["peace","cattle"],"peopleInVerse":[]},"23":{"text":"Take thou away from me the noise of thy songs; for I will not hear the melody of thy viols.","ref":"Amos 5:23","synthesized":"Take away from Me the noise of your songs! I will not listen to the music of your harps.","sources":{"KJV":{"text":"Take thou away from me the noise of thy songs; for I will not hear the melody of thy viols."},"BSB":{"text":"Take away from Me the noise of your songs! I will not listen to the music of your harps."}},"definableWords":[],"peopleInVerse":[]},"24":{"text":"But let judgment run down as waters, and righteousness as a mighty stream.","ref":"Amos 5:24","synthesized":"But let justice roll on like a river, and righteousness like an ever-flowing stream.","sources":{"KJV":{"text":"But let judgment run down as waters, and righteousness as a mighty stream."},"BSB":{"text":"But let justice roll on like a river, and righteousness like an ever-flowing stream."}},"definableWords":["justice","righteousness"],"peopleInVerse":[]},"25":{"text":"Have ye offered unto me sacrifices and offerings in the wilderness forty years, O house of Israel?","ref":"Amos 5:25","synthesized":"Did you bring Me sacrifices and offerings forty years in the wilderness, O house of Israel?","sources":{"KJV":{"text":"Have ye offered unto me sacrifices and offerings in the wilderness forty years, O house of Israel?"},"BSB":{"text":"Did you bring Me sacrifices and offerings forty years in the wilderness, O house of Israel?"}},"definableWords":["years","house","Israel"],"peopleInVerse":[]},"26":{"text":"But ye have borne the tabernacle of your Moloch and Chiun your images, the star of your god, which ye made to yourselves.","ref":"Amos 5:26","synthesized":"You have taken along Sakkuth your king and Kaiwan your star god, the idols you made for yourselves.","sources":{"KJV":{"text":"But ye have borne the tabernacle of your Moloch and Chiun your images, the star of your god, which ye made to yourselves."},"BSB":{"text":"You have taken along Sakkuth your king and Kaiwan your star god, the idols you made for yourselves."}},"definableWords":["king","God","made"],"peopleInVerse":[]},"27":{"text":"Therefore will I cause you to go into captivity beyond Damascus, saith the LORD, whose name is The God of hosts.","ref":"Amos 5:27","synthesized":"Therefore I will send you into exile beyond Damascus,” says the LORD, whose name is the God of Hosts.","sources":{"KJV":{"text":"Therefore will I cause you to go into captivity beyond Damascus, saith the LORD, whose name is The God of hosts."},"BSB":{"text":"Therefore I will send you into exile beyond Damascus,” says the LORD, whose name is the God of Hosts."}},"definableWords":["LORD","name","God"],"peopleInVerse":[]}}},"6":{"chapter":"6","title":"WOE TO THEM AT EASE IN ZION","verses":{"1":{"text":"Woe to them that are at ease in Zion, and trust in the mountain of Samaria, which are named chief of the nations, to whom the house of Israel came!","ref":"Amos 6:1","synthesized":"Woe to those at ease in Zion and those secure on Mount Samaria, the distinguished ones of the foremost nation, to whom the house of Israel comes.","sources":{"KJV":{"text":"Woe to them that are at ease in Zion, and trust in the mountain of Samaria, which are named chief of the nations, to whom the house of Israel came!"},"BSB":{"text":"Woe to those at ease in Zion and those secure on Mount Samaria, the distinguished ones of the foremost nation, to whom the house of Israel comes."}},"definableWords":["Zion","Samaria","nation","house","Israel"],"peopleInVerse":[]},"2":{"text":"Pass ye unto Calneh, and see; and from thence go ye to Hamath the great: then go down to Gath of the Philistines: be they better than these kingdoms? or their border greater than your border?","ref":"Amos 6:2","synthesized":"Cross over to Calneh and see; go from there to the great Hamath; then go down to Gath of the Philistines. Are you better than these kingdoms? Is their territory larger than yours?","sources":{"KJV":{"text":"Pass ye unto Calneh, and see; and from thence go ye to Hamath the great: then go down to Gath of the Philistines: be they better than these kingdoms? or their border greater than your border?"},"BSB":{"text":"Cross over to Calneh and see; go from there to the great Hamath; then go down to Gath of the Philistines. Are you better than these kingdoms? Is their territory larger than yours?"}},"definableWords":["see","great"],"peopleInVerse":[]},"3":{"text":"Ye that put far away the evil day, and cause the seat of violence to come near;","ref":"Amos 6:3","synthesized":"You dismiss the day of calamity and bring near a reign of violence.","sources":{"KJV":{"text":"Ye that put far away the evil day, and cause the seat of violence to come near;"},"BSB":{"text":"You dismiss the day of calamity and bring near a reign of violence."}},"definableWords":["day","reign"],"peopleInVerse":[]},"4":{"text":"That lie upon beds of ivory, and stretch themselves upon their couches, and eat the lambs out of the flock, and the calves out of the midst of the stall;","ref":"Amos 6:4","synthesized":"You lie on beds inlaid with ivory, and lounge upon your couches. You dine on lambs from the flock and calves from the stall.","sources":{"KJV":{"text":"That lie upon beds of ivory, and stretch themselves upon their couches, and eat the lambs out of the flock, and the calves out of the midst of the stall;"},"BSB":{"text":"You lie on beds inlaid with ivory, and lounge upon your couches. You dine on lambs from the flock and calves from the stall."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"That chant to the sound of the viol, and invent to themselves instruments of musick, like David;","ref":"Amos 6:5","synthesized":"You improvise songs on the harp like David and invent your own musical instruments.","sources":{"KJV":{"text":"That chant to the sound of the viol, and invent to themselves instruments of musick, like David;"},"BSB":{"text":"You improvise songs on the harp like David and invent your own musical instruments."}},"definableWords":[],"peopleInVerse":["David"]},"6":{"text":"That drink wine in bowls, and anoint themselves with the chief ointments: but they are not grieved for the affliction of Joseph.","ref":"Amos 6:6","synthesized":"You drink wine by the bowlful and anoint yourselves with the finest oils, but you fail to grieve over the ruin of Joseph.","sources":{"KJV":{"text":"That drink wine in bowls, and anoint themselves with the chief ointments: but they are not grieved for the affliction of Joseph."},"BSB":{"text":"You drink wine by the bowlful and anoint yourselves with the finest oils, but you fail to grieve over the ruin of Joseph."}},"definableWords":["anoint","Joseph"],"peopleInVerse":["Joseph"]},"7":{"text":"Therefore now shall they go captive with the first that go captive, and the banquet of them that stretched themselves shall be removed.","ref":"Amos 6:7","synthesized":"Therefore, you will now go into exile as the first of the captives, and your feasting and lounging will come to an end.","sources":{"KJV":{"text":"Therefore now shall they go captive with the first that go captive, and the banquet of them that stretched themselves shall be removed."},"BSB":{"text":"Therefore, you will now go into exile as the first of the captives, and your feasting and lounging will come to an end."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"The Lord GOD hath sworn by himself, saith the LORD the God of hosts, I abhor the excellency of Jacob, and hate his palaces: therefore will I deliver up the city with all that is therein.","ref":"Amos 6:8","synthesized":"The Lord GOD has sworn by Himself—the LORD, the God of Hosts, has declared:  “I abhor Jacob’s pride and detest his citadels, so I will deliver up the city and everything in it.”","sources":{"KJV":{"text":"The Lord GOD hath sworn by himself, saith the LORD the God of hosts, I abhor the excellency of Jacob, and hate his palaces: therefore will I deliver up the city with all that is therein."},"BSB":{"text":"The Lord GOD has sworn by Himself—the LORD, the God of Hosts, has declared:  “I abhor Jacob’s pride and detest his citadels, so I will deliver up the city and everything in it.”"}},"definableWords":["Lord","God","LORD","Jacob","deliver"],"peopleInVerse":["Jacob"]},"9":{"text":"And it shall come to pass, if there remain ten men in one house, that they shall die.","ref":"Amos 6:9","synthesized":"And if there are ten men left in one house, they too will die.","sources":{"KJV":{"text":"And it shall come to pass, if there remain ten men in one house, that they shall die."},"BSB":{"text":"And if there are ten men left in one house, they too will die."}},"definableWords":["men","one","house","die"],"peopleInVerse":[]},"10":{"text":"And a man’s uncle shall take him up, and he that burneth him, to bring out the bones out of the house, and shall say unto him that is by the sides of the house, Is there yet any with thee? and he shall say, No. Then shall he say, Hold thy tongue: for we may not make mention of the name of the LORD.","ref":"Amos 6:10","synthesized":"And when the relative who is to burn the bodies picks them up to remove them from the house, he will call to one inside, “Is anyone else with you?”  “None,” that person will answer.  “Silence,” the relative will retort, “for the name of the LORD must not be invoked.”","sources":{"KJV":{"text":"And a man’s uncle shall take him up, and he that burneth him, to bring out the bones out of the house, and shall say unto him that is by the sides of the house, Is there yet any with thee? and he shall say, No. Then shall he say, Hold thy tongue: for we may not make mention of the name of the LORD."},"BSB":{"text":"And when the relative who is to burn the bodies picks them up to remove them from the house, he will call to one inside, “Is anyone else with you?”  “None,” that person will answer.  “Silence,” the relative will retort, “for the name of the LORD must not be invoked.”"}},"definableWords":["house","one","name","LORD"],"peopleInVerse":[]},"11":{"text":"For, behold, the LORD commandeth, and he will smite the great house with breaches, and the little house with clefts.","ref":"Amos 6:11","synthesized":"For the LORD gives a command:  “The great house will be smashed to pieces, and the small house to rubble.”","sources":{"KJV":{"text":"For, behold, the LORD commandeth, and he will smite the great house with breaches, and the little house with clefts."},"BSB":{"text":"For the LORD gives a command:  “The great house will be smashed to pieces, and the small house to rubble.”"}},"definableWords":["LORD","great","house"],"peopleInVerse":[]},"12":{"text":"Shall horses run upon the rock? will one plow there with oxen? for ye have turned judgment into gall, and the fruit of righteousness into hemlock:","ref":"Amos 6:12","synthesized":"“Do horses gallop on the cliffs? Does one plow the sea with oxen? But you have turned justice into poison and the fruit of righteousness into wormwood—","sources":{"KJV":{"text":"Shall horses run upon the rock? will one plow there with oxen? for ye have turned judgment into gall, and the fruit of righteousness into hemlock:"},"BSB":{"text":"“Do horses gallop on the cliffs? Does one plow the sea with oxen? But you have turned justice into poison and the fruit of righteousness into wormwood—"}},"definableWords":["one","sea","justice","righteousness"],"peopleInVerse":[]},"13":{"text":"Ye which rejoice in a thing of nought, which say, Have we not taken to us horns by our own strength?","ref":"Amos 6:13","synthesized":"you who rejoice in Lo-debar and say, ‘Did we not take Karnaim by our own strength?’","sources":{"KJV":{"text":"Ye which rejoice in a thing of nought, which say, Have we not taken to us horns by our own strength?"},"BSB":{"text":"you who rejoice in Lo-debar and say, ‘Did we not take Karnaim by our own strength?’"}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"But, behold, I will raise up against you a nation, O house of Israel, saith the LORD the God of hosts; and they shall afflict you from the entering in of Hemath unto the river of the wilderness.","ref":"Amos 6:14","synthesized":"For behold, I will raise up a nation against you, O house of Israel,” declares the LORD, the God of Hosts, “and they will oppress you from Lebo-hamath to the Brook of the Arabah.”","sources":{"KJV":{"text":"But, behold, I will raise up against you a nation, O house of Israel, saith the LORD the God of hosts; and they shall afflict you from the entering in of Hemath unto the river of the wilderness."},"BSB":{"text":"For behold, I will raise up a nation against you, O house of Israel,” declares the LORD, the God of Hosts, “and they will oppress you from Lebo-hamath to the Brook of the Arabah.”"}},"definableWords":["nation","house","Israel","LORD","God"],"peopleInVerse":[]}}},"7":{"chapter":"7","title":"AMOS' VISIONS — LOCUSTS, FIRE, PLUMB LINE","verses":{"1":{"text":"Thus hath the Lord GOD shewed unto me; and, behold, he formed grasshoppers in the beginning of the shooting up of the latter growth; and, lo, it was the latter growth after the king’s mowings.","ref":"Amos 7:1","synthesized":"This is what the Lord GOD showed me: He was preparing swarms of locusts just after the king’s harvest, as the late spring crop was coming up.","sources":{"KJV":{"text":"Thus hath the Lord GOD shewed unto me; and, behold, he formed grasshoppers in the beginning of the shooting up of the latter growth; and, lo, it was the latter growth after the king’s mowings."},"BSB":{"text":"This is what the Lord GOD showed me: He was preparing swarms of locusts just after the king’s harvest, as the late spring crop was coming up."}},"definableWords":["Lord","God","king"],"peopleInVerse":[]},"2":{"text":"And it came to pass, that when they had made an end of eating the grass of the land, then I said, O Lord GOD, forgive, I beseech thee: by whom shall Jacob arise? for he is small.","ref":"Amos 7:2","synthesized":"And when the locusts had eaten every green plant in the land, I said, “Lord GOD, please forgive! How will Jacob survive, since he is so small?”","sources":{"KJV":{"text":"And it came to pass, that when they had made an end of eating the grass of the land, then I said, O Lord GOD, forgive, I beseech thee: by whom shall Jacob arise? for he is small."},"BSB":{"text":"And when the locusts had eaten every green plant in the land, I said, “Lord GOD, please forgive! How will Jacob survive, since he is so small?”"}},"definableWords":["land","Lord","God","forgive","Jacob"],"peopleInVerse":["Jacob"]},"3":{"text":"The LORD repented for this: It shall not be, saith the LORD.","ref":"Amos 7:3","synthesized":"So the LORD relented from this plan. “It will not happen,” He said.","sources":{"KJV":{"text":"The LORD repented for this: It shall not be, saith the LORD."},"BSB":{"text":"So the LORD relented from this plan. “It will not happen,” He said."}},"definableWords":["LORD"],"peopleInVerse":[]},"4":{"text":"Thus hath the Lord GOD shewed unto me: and, behold, the Lord GOD called to contend by fire, and it devoured the great deep, and did eat up a part.","ref":"Amos 7:4","synthesized":"This is what the Lord GOD showed me: The Lord GOD was calling for judgment by fire. It consumed the great deep and devoured the land.","sources":{"KJV":{"text":"Thus hath the Lord GOD shewed unto me: and, behold, the Lord GOD called to contend by fire, and it devoured the great deep, and did eat up a part."},"BSB":{"text":"This is what the Lord GOD showed me: The Lord GOD was calling for judgment by fire. It consumed the great deep and devoured the land."}},"definableWords":["Lord","God","judgment","great","deep","land"],"peopleInVerse":[]},"5":{"text":"Then said I, O Lord GOD, cease, I beseech thee: by whom shall Jacob arise? for he is small.","ref":"Amos 7:5","synthesized":"Then I said, “Lord GOD, please stop! How will Jacob survive, since he is so small?”","sources":{"KJV":{"text":"Then said I, O Lord GOD, cease, I beseech thee: by whom shall Jacob arise? for he is small."},"BSB":{"text":"Then I said, “Lord GOD, please stop! How will Jacob survive, since he is so small?”"}},"definableWords":["Lord","God","Jacob"],"peopleInVerse":["Jacob"]},"6":{"text":"The LORD repented for this: This also shall not be, saith the Lord GOD.","ref":"Amos 7:6","synthesized":"So the LORD relented from this plan. “It will not happen either,” said the Lord GOD.","sources":{"KJV":{"text":"The LORD repented for this: This also shall not be, saith the Lord GOD."},"BSB":{"text":"So the LORD relented from this plan. “It will not happen either,” said the Lord GOD."}},"definableWords":["LORD","Lord","God"],"peopleInVerse":[]},"7":{"text":"Thus he shewed me: and, behold, the LORD stood upon a wall made by a plumbline, with a plumbline in his hand.","ref":"Amos 7:7","synthesized":"This is what He showed me: Behold, the Lord was standing by a wall true to plumb, with a plumb line in His hand.","sources":{"KJV":{"text":"Thus he shewed me: and, behold, the LORD stood upon a wall made by a plumbline, with a plumbline in his hand."},"BSB":{"text":"This is what He showed me: Behold, the Lord was standing by a wall true to plumb, with a plumb line in His hand."}},"definableWords":["Lord"],"peopleInVerse":[]},"8":{"text":"And the LORD said unto me, Amos, what seest thou? And I said, A plumbline. Then said the LORD, Behold, I will set a plumbline in the midst of my people Israel: I will not again pass by them any more:","ref":"Amos 7:8","synthesized":"“Amos, what do you see?” asked the LORD.  “A plumb line,” I replied.  “Behold,” said the Lord, “I am setting a plumb line among My people Israel; I will no longer spare them:","sources":{"KJV":{"text":"And the LORD said unto me, Amos, what seest thou? And I said, A plumbline. Then said the LORD, Behold, I will set a plumbline in the midst of my people Israel: I will not again pass by them any more:"},"BSB":{"text":"“Amos, what do you see?” asked the LORD.  “A plumb line,” I replied.  “Behold,” said the Lord, “I am setting a plumb line among My people Israel; I will no longer spare them:"}},"definableWords":["see","LORD","Lord","people","Israel"],"peopleInVerse":[]},"9":{"text":"And the high places of Isaac shall be desolate, and the sanctuaries of Israel shall be laid waste; and I will rise against the house of Jeroboam with the sword.","ref":"Amos 7:9","synthesized":"The high places of Isaac will be deserted, and the sanctuaries of Israel will be laid waste; and I will rise up against the house of Jeroboam with My sword.”","sources":{"KJV":{"text":"And the high places of Isaac shall be desolate, and the sanctuaries of Israel shall be laid waste; and I will rise against the house of Jeroboam with the sword."},"BSB":{"text":"The high places of Isaac will be deserted, and the sanctuaries of Israel will be laid waste; and I will rise up against the house of Jeroboam with My sword.”"}},"definableWords":["Isaac","Israel","house"],"peopleInVerse":["Isaac"]},"10":{"text":"Then Amaziah the priest of Bethel sent to Jeroboam king of Israel, saying, Amos hath conspired against thee in the midst of the house of Israel: the land is not able to bear all his words.","ref":"Amos 7:10","synthesized":"Then Amaziah the priest of Bethel sent word to Jeroboam king of Israel, saying, “Amos has conspired against you in the midst of the house of Israel. The land cannot bear all his words,","sources":{"KJV":{"text":"Then Amaziah the priest of Bethel sent to Jeroboam king of Israel, saying, Amos hath conspired against thee in the midst of the house of Israel: the land is not able to bear all his words."},"BSB":{"text":"Then Amaziah the priest of Bethel sent word to Jeroboam king of Israel, saying, “Amos has conspired against you in the midst of the house of Israel. The land cannot bear all his words,"}},"definableWords":["priest","Bethel","word","king","Israel","house","land"],"peopleInVerse":[]},"11":{"text":"For thus Amos saith, Jeroboam shall die by the sword, and Israel shall surely be led away captive out of their own land.","ref":"Amos 7:11","synthesized":"for this is what Amos has said:  ‘Jeroboam will die by the sword, and Israel will surely go into exile, away from their homeland.’”","sources":{"KJV":{"text":"For thus Amos saith, Jeroboam shall die by the sword, and Israel shall surely be led away captive out of their own land."},"BSB":{"text":"for this is what Amos has said:  ‘Jeroboam will die by the sword, and Israel will surely go into exile, away from their homeland.’”"}},"definableWords":["die","Israel"],"peopleInVerse":[]},"12":{"text":"Also Amaziah said unto Amos, O thou seer, go, flee thee away into the land of Judah, and there eat bread, and prophesy there:","ref":"Amos 7:12","synthesized":"And Amaziah said to Amos, “Go away, you seer! Flee to the land of Judah; earn your bread there and do your prophesying there.","sources":{"KJV":{"text":"Also Amaziah said unto Amos, O thou seer, go, flee thee away into the land of Judah, and there eat bread, and prophesy there:"},"BSB":{"text":"And Amaziah said to Amos, “Go away, you seer! Flee to the land of Judah; earn your bread there and do your prophesying there."}},"definableWords":["land","Judah"],"peopleInVerse":[]},"13":{"text":"But prophesy not again any more at Bethel: for it is the king’s chapel, and it is the king’s court.","ref":"Amos 7:13","synthesized":"But never prophesy at Bethel again, because it is the sanctuary of the king and the temple of the kingdom.”","sources":{"KJV":{"text":"But prophesy not again any more at Bethel: for it is the king’s chapel, and it is the king’s court."},"BSB":{"text":"But never prophesy at Bethel again, because it is the sanctuary of the king and the temple of the kingdom.”"}},"definableWords":["Bethel","king","temple","kingdom"],"peopleInVerse":[]},"14":{"text":"Then answered Amos, and said to Amaziah, I was no prophet, neither was I a prophet’s son; but I was an herdman, and a gatherer of sycomore fruit:","ref":"Amos 7:14","synthesized":"“I was not a prophet,” Amos replied, “nor was I the son of a prophet; rather, I was a herdsman and a tender of sycamore-fig trees.","sources":{"KJV":{"text":"Then answered Amos, and said to Amaziah, I was no prophet, neither was I a prophet’s son; but I was an herdman, and a gatherer of sycomore fruit:"},"BSB":{"text":"“I was not a prophet,” Amos replied, “nor was I the son of a prophet; rather, I was a herdsman and a tender of sycamore-fig trees."}},"definableWords":["prophet","son","trees"],"peopleInVerse":[]},"15":{"text":"And the LORD took me as I followed the flock, and the LORD said unto me, Go, prophesy unto my people Israel.","ref":"Amos 7:15","synthesized":"But the LORD took me from following the flock and said to me, ‘Go, prophesy to My people Israel.’","sources":{"KJV":{"text":"And the LORD took me as I followed the flock, and the LORD said unto me, Go, prophesy unto my people Israel."},"BSB":{"text":"But the LORD took me from following the flock and said to me, ‘Go, prophesy to My people Israel.’"}},"definableWords":["LORD","people","Israel"],"peopleInVerse":[]},"16":{"text":"Now therefore hear thou the word of the LORD: Thou sayest, Prophesy not against Israel, and drop not thy word against the house of Isaac.","ref":"Amos 7:16","synthesized":"Now, therefore, hear the word of the LORD. You say:  ‘Do not prophesy against Israel; do not preach against the house of Isaac.’","sources":{"KJV":{"text":"Now therefore hear thou the word of the LORD: Thou sayest, Prophesy not against Israel, and drop not thy word against the house of Isaac."},"BSB":{"text":"Now, therefore, hear the word of the LORD. You say:  ‘Do not prophesy against Israel; do not preach against the house of Isaac.’"}},"definableWords":["hear","word","LORD","Israel","house","Isaac"],"peopleInVerse":["Isaac"]},"17":{"text":"Therefore thus saith the LORD; Thy wife shall be an harlot in the city, and thy sons and thy daughters shall fall by the sword, and thy land shall be divided by line; and thou shalt die in a polluted land: and Israel shall surely go into captivity forth of his land.","ref":"Amos 7:17","synthesized":"Therefore this is what the LORD says:  ‘Your wife will become a prostitute in the city, and your sons and daughters will fall by the sword. Your land will be divided by a measuring line, and you yourself will die on pagan soil. And Israel will surely go into exile, away from their homeland.’”","sources":{"KJV":{"text":"Therefore thus saith the LORD; Thy wife shall be an harlot in the city, and thy sons and thy daughters shall fall by the sword, and thy land shall be divided by line; and thou shalt die in a polluted land: and Israel shall surely go into captivity forth of his land."},"BSB":{"text":"Therefore this is what the LORD says:  ‘Your wife will become a prostitute in the city, and your sons and daughters will fall by the sword. Your land will be divided by a measuring line, and you yourself will die on pagan soil. And Israel will surely go into exile, away from their homeland.’”"}},"definableWords":["LORD","wife","sons","daughters","land","die","Israel"],"peopleInVerse":[]}}},"8":{"chapter":"8","title":"THE FAMINE OF HEARING GOD'S WORDS","verses":{"1":{"text":"Thus hath the Lord GOD shewed unto me: and behold a basket of summer fruit.","ref":"Amos 8:1","synthesized":"This is what the Lord GOD showed me: I saw a basket of summer fruit.","sources":{"KJV":{"text":"Thus hath the Lord GOD shewed unto me: and behold a basket of summer fruit."},"BSB":{"text":"This is what the Lord GOD showed me: I saw a basket of summer fruit."}},"definableWords":["Lord","God","saw"],"peopleInVerse":[]},"2":{"text":"And he said, Amos, what seest thou? And I said, A basket of summer fruit. Then said the LORD unto me, The end is come upon my people of Israel; I will not again pass by them any more.","ref":"Amos 8:2","synthesized":"“Amos, what do you see?” He asked.  “A basket of summer fruit,” I replied.  So the LORD said to me, “The end has come for My people Israel; I will no longer spare them.”","sources":{"KJV":{"text":"And he said, Amos, what seest thou? And I said, A basket of summer fruit. Then said the LORD unto me, The end is come upon my people of Israel; I will not again pass by them any more."},"BSB":{"text":"“Amos, what do you see?” He asked.  “A basket of summer fruit,” I replied.  So the LORD said to me, “The end has come for My people Israel; I will no longer spare them.”"}},"definableWords":["see","LORD","people","Israel"],"peopleInVerse":[]},"3":{"text":"And the songs of the temple shall be howlings in that day, saith the Lord GOD: there shall be many dead bodies in every place; they shall cast them forth with silence.","ref":"Amos 8:3","synthesized":"“In that day,” declares the Lord GOD, “the songs of the temple will turn to wailing. Many will be the corpses, strewn in silence everywhere!”","sources":{"KJV":{"text":"And the songs of the temple shall be howlings in that day, saith the Lord GOD: there shall be many dead bodies in every place; they shall cast them forth with silence."},"BSB":{"text":"“In that day,” declares the Lord GOD, “the songs of the temple will turn to wailing. Many will be the corpses, strewn in silence everywhere!”"}},"definableWords":["day","Lord","God","temple"],"peopleInVerse":[]},"4":{"text":"Hear this, O ye that swallow up the needy, even to make the poor of the land to fail,","ref":"Amos 8:4","synthesized":"Hear this, you who trample the needy, who do away with the poor of the land,","sources":{"KJV":{"text":"Hear this, O ye that swallow up the needy, even to make the poor of the land to fail,"},"BSB":{"text":"Hear this, you who trample the needy, who do away with the poor of the land,"}},"definableWords":["hear","land"],"peopleInVerse":[]},"5":{"text":"Saying, When will the new moon be gone, that we may sell corn? and the sabbath, that we may set forth wheat, making the ephah small, and the shekel great, and falsifying the balances by deceit?","ref":"Amos 8:5","synthesized":"asking, “When will the New Moon be over, that we may sell grain? When will the Sabbath end, that we may market wheat? Let us reduce the ephah and increase the shekel; let us cheat with dishonest scales.","sources":{"KJV":{"text":"Saying, When will the new moon be gone, that we may sell corn? and the sabbath, that we may set forth wheat, making the ephah small, and the shekel great, and falsifying the balances by deceit?"},"BSB":{"text":"asking, “When will the New Moon be over, that we may sell grain? When will the Sabbath end, that we may market wheat? Let us reduce the ephah and increase the shekel; let us cheat with dishonest scales."}},"definableWords":["Sabbath"],"peopleInVerse":[]},"6":{"text":"That we may buy the poor for silver, and the needy for a pair of shoes; yea, and sell the refuse of the wheat?","ref":"Amos 8:6","synthesized":"Let us buy the poor with silver and the needy for a pair of sandals, selling even the chaff with the wheat!”","sources":{"KJV":{"text":"That we may buy the poor for silver, and the needy for a pair of shoes; yea, and sell the refuse of the wheat?"},"BSB":{"text":"Let us buy the poor with silver and the needy for a pair of sandals, selling even the chaff with the wheat!”"}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"The LORD hath sworn by the excellency of Jacob, Surely I will never forget any of their works.","ref":"Amos 8:7","synthesized":"The LORD has sworn by the Pride of Jacob:  “I will never forget any of their deeds.","sources":{"KJV":{"text":"The LORD hath sworn by the excellency of Jacob, Surely I will never forget any of their works."},"BSB":{"text":"The LORD has sworn by the Pride of Jacob:  “I will never forget any of their deeds."}},"definableWords":["LORD","Jacob"],"peopleInVerse":["Jacob"]},"8":{"text":"Shall not the land tremble for this, and every one mourn that dwelleth therein? and it shall rise up wholly as a flood; and it shall be cast out and drowned, as by the flood of Egypt.","ref":"Amos 8:8","synthesized":"Will not the land quake for this, and all its dwellers mourn? All of it will swell like the Nile; it will surge and then subside like the Nile in Egypt.","sources":{"KJV":{"text":"Shall not the land tremble for this, and every one mourn that dwelleth therein? and it shall rise up wholly as a flood; and it shall be cast out and drowned, as by the flood of Egypt."},"BSB":{"text":"Will not the land quake for this, and all its dwellers mourn? All of it will swell like the Nile; it will surge and then subside like the Nile in Egypt."}},"definableWords":["land","Egypt"],"peopleInVerse":[]},"9":{"text":"And it shall come to pass in that day, saith the Lord GOD, that I will cause the sun to go down at noon, and I will darken the earth in the clear day:","ref":"Amos 8:9","synthesized":"And in that day, declares the Lord GOD, I will make the sun go down at noon, and I will darken the earth in the daytime.","sources":{"KJV":{"text":"And it shall come to pass in that day, saith the Lord GOD, that I will cause the sun to go down at noon, and I will darken the earth in the clear day:"},"BSB":{"text":"And in that day, declares the Lord GOD, I will make the sun go down at noon, and I will darken the earth in the daytime."}},"definableWords":["day","Lord","God","make","earth"],"peopleInVerse":[]},"10":{"text":"And I will turn your feasts into mourning, and all your songs into lamentation; and I will bring up sackcloth upon all loins, and baldness upon every head; and I will make it as the mourning of an only son, and the end thereof as a bitter day.","ref":"Amos 8:10","synthesized":"I will turn your feasts into mourning and all your songs into lamentation. I will cause everyone to wear sackcloth and every head to be shaved. I will make it like a time of mourning for an only son, and its outcome like a bitter day.","sources":{"KJV":{"text":"And I will turn your feasts into mourning, and all your songs into lamentation; and I will bring up sackcloth upon all loins, and baldness upon every head; and I will make it as the mourning of an only son, and the end thereof as a bitter day."},"BSB":{"text":"I will turn your feasts into mourning and all your songs into lamentation. I will cause everyone to wear sackcloth and every head to be shaved. I will make it like a time of mourning for an only son, and its outcome like a bitter day."}},"definableWords":["make","son","day"],"peopleInVerse":[]},"11":{"text":"Behold, the days come, saith the Lord GOD, that I will send a famine in the land, not a famine of bread, nor a thirst for water, but of hearing the words of the LORD:","ref":"Amos 8:11","synthesized":"Behold, the days are coming, declares the Lord GOD, when I will send a famine on the land— not a famine of bread or a thirst for water, but a famine of hearing the words of the LORD.","sources":{"KJV":{"text":"Behold, the days come, saith the Lord GOD, that I will send a famine in the land, not a famine of bread, nor a thirst for water, but of hearing the words of the LORD:"},"BSB":{"text":"Behold, the days are coming, declares the Lord GOD, when I will send a famine on the land— not a famine of bread or a thirst for water, but a famine of hearing the words of the LORD."}},"definableWords":["days","Lord","God","land","or","water","LORD"],"peopleInVerse":[]},"12":{"text":"And they shall wander from sea to sea, and from the north even to the east, they shall run to and fro to seek the word of the LORD, and shall not find it.","ref":"Amos 8:12","synthesized":"People will stagger from sea to sea and roam from north to east, seeking the word of the LORD, but they will not find it.","sources":{"KJV":{"text":"And they shall wander from sea to sea, and from the north even to the east, they shall run to and fro to seek the word of the LORD, and shall not find it."},"BSB":{"text":"People will stagger from sea to sea and roam from north to east, seeking the word of the LORD, but they will not find it."}},"definableWords":["people","sea","word","LORD"],"peopleInVerse":[]},"13":{"text":"In that day shall the fair virgins and young men faint for thirst.","ref":"Amos 8:13","synthesized":"In that day the lovely young women— the young men as well— will faint from thirst.","sources":{"KJV":{"text":"In that day shall the fair virgins and young men faint for thirst."},"BSB":{"text":"In that day the lovely young women— the young men as well— will faint from thirst."}},"definableWords":["day","women","men"],"peopleInVerse":[]},"14":{"text":"They that swear by the sin of Samaria, and say, Thy god, O Dan, liveth; and, The manner of Beersheba liveth; even they shall fall, and never rise up again.","ref":"Amos 8:14","synthesized":"Those who swear by the guilt of Samaria and say, ‘As surely as your god lives, O Dan,’ or, ‘As surely as the way of Beersheba lives’— they will fall, never to rise again.”","sources":{"KJV":{"text":"They that swear by the sin of Samaria, and say, Thy god, O Dan, liveth; and, The manner of Beersheba liveth; even they shall fall, and never rise up again."},"BSB":{"text":"Those who swear by the guilt of Samaria and say, ‘As surely as your god lives, O Dan,’ or, ‘As surely as the way of Beersheba lives’— they will fall, never to rise again.”"}},"definableWords":["Samaria","God","or","way","Beersheba"],"peopleInVerse":[]}}},"9":{"chapter":"9","title":"I WILL RAISE UP THE TABERNACLE OF DAVID","verses":{"1":{"text":"I saw the LORD standing upon the altar: and he said, Smite the lintel of the door, that the posts may shake: and cut them in the head, all of them; and I will slay the last of them with the sword: he that fleeth of them shall not flee away, and he that escapeth of them shall not be delivered.","ref":"Amos 9:1","synthesized":"I saw the Lord standing beside the altar, and He said:  “Strike the tops of the pillars so that the thresholds shake. Topple them on the heads of all the people, and I will kill the rest with the sword. None of those who flee will get away; none of the fugitives will escape.","sources":{"KJV":{"text":"I saw the LORD standing upon the altar: and he said, Smite the lintel of the door, that the posts may shake: and cut them in the head, all of them; and I will slay the last of them with the sword: he that fleeth of them shall not flee away, and he that escapeth of them shall not be delivered."},"BSB":{"text":"I saw the Lord standing beside the altar, and He said:  “Strike the tops of the pillars so that the thresholds shake. Topple them on the heads of all the people, and I will kill the rest with the sword. None of those who flee will get away; none of the fugitives will escape."}},"definableWords":["saw","Lord","altar","people","rest"],"peopleInVerse":[]},"2":{"text":"Though they dig into hell, thence shall mine hand take them; though they climb up to heaven, thence will I bring them down:","ref":"Amos 9:2","synthesized":"Though they dig down to Sheol, from there My hand will take them; and though they climb up to heaven, from there I will pull them down.","sources":{"KJV":{"text":"Though they dig into hell, thence shall mine hand take them; though they climb up to heaven, thence will I bring them down:"},"BSB":{"text":"Though they dig down to Sheol, from there My hand will take them; and though they climb up to heaven, from there I will pull them down."}},"definableWords":["heaven"],"peopleInVerse":[]},"3":{"text":"And though they hide themselves in the top of Carmel, I will search and take them out thence; and though they be hid from my sight in the bottom of the sea, thence will I command the serpent, and he shall bite them:","ref":"Amos 9:3","synthesized":"Though they hide themselves atop Carmel, there I will track them and seize them; and though they hide from Me at the bottom of the sea, there I will command the serpent to bite them.","sources":{"KJV":{"text":"And though they hide themselves in the top of Carmel, I will search and take them out thence; and though they be hid from my sight in the bottom of the sea, thence will I command the serpent, and he shall bite them:"},"BSB":{"text":"Though they hide themselves atop Carmel, there I will track them and seize them; and though they hide from Me at the bottom of the sea, there I will command the serpent to bite them."}},"definableWords":["sea","serpent"],"peopleInVerse":[]},"4":{"text":"And though they go into captivity before their enemies, thence will I command the sword, and it shall slay them: and I will set mine eyes upon them for evil, and not for good.","ref":"Amos 9:4","synthesized":"Though they are driven by their enemies into captivity, there I will command the sword to slay them. I will fix My eyes upon them for harm and not for good.”","sources":{"KJV":{"text":"And though they go into captivity before their enemies, thence will I command the sword, and it shall slay them: and I will set mine eyes upon them for evil, and not for good."},"BSB":{"text":"Though they are driven by their enemies into captivity, there I will command the sword to slay them. I will fix My eyes upon them for harm and not for good.”"}},"definableWords":["good"],"peopleInVerse":[]},"5":{"text":"And the Lord GOD of hosts is he that toucheth the land, and it shall melt, and all that dwell therein shall mourn: and it shall rise up wholly like a flood; and shall be drowned, as by the flood of Egypt.","ref":"Amos 9:5","synthesized":"The Lord GOD of Hosts, He who touches the earth and it melts, and all its dwellers mourn— all the land rises like the Nile, then sinks like the river of Egypt—","sources":{"KJV":{"text":"And the Lord GOD of hosts is he that toucheth the land, and it shall melt, and all that dwell therein shall mourn: and it shall rise up wholly like a flood; and shall be drowned, as by the flood of Egypt."},"BSB":{"text":"The Lord GOD of Hosts, He who touches the earth and it melts, and all its dwellers mourn— all the land rises like the Nile, then sinks like the river of Egypt—"}},"definableWords":["Lord","God","earth","land","Egypt"],"peopleInVerse":[]},"6":{"text":"It is he that buildeth his stories in the heaven, and hath founded his troop in the earth; he that calleth for the waters of the sea, and poureth them out upon the face of the earth: The LORD is his name.","ref":"Amos 9:6","synthesized":"He builds His upper rooms in the heavens and founds His vault upon the earth. He summons the waters of the sea and pours them over the face of the earth. The LORD is His name.","sources":{"KJV":{"text":"It is he that buildeth his stories in the heaven, and hath founded his troop in the earth; he that calleth for the waters of the sea, and poureth them out upon the face of the earth: The LORD is his name."},"BSB":{"text":"He builds His upper rooms in the heavens and founds His vault upon the earth. He summons the waters of the sea and pours them over the face of the earth. The LORD is His name."}},"definableWords":["heavens","earth","waters","sea","LORD","name"],"peopleInVerse":[]},"7":{"text":"Are ye not as children of the Ethiopians unto me, O children of Israel? saith the LORD. Have not I brought up Israel out of the land of Egypt? and the Philistines from Caphtor, and the Syrians from Kir?","ref":"Amos 9:7","synthesized":"“Are you not like the Cushites to Me, O children of Israel?” declares the LORD. “Did I not bring Israel up from the land of Egypt, the Philistines from Caphtor, and the Arameans from Kir?","sources":{"KJV":{"text":"Are ye not as children of the Ethiopians unto me, O children of Israel? saith the LORD. Have not I brought up Israel out of the land of Egypt? and the Philistines from Caphtor, and the Syrians from Kir?"},"BSB":{"text":"“Are you not like the Cushites to Me, O children of Israel?” declares the LORD. “Did I not bring Israel up from the land of Egypt, the Philistines from Caphtor, and the Arameans from Kir?"}},"definableWords":["Israel","LORD","land","Egypt"],"peopleInVerse":[]},"8":{"text":"Behold, the eyes of the Lord GOD are upon the sinful kingdom, and I will destroy it from off the face of the earth; saving that I will not utterly destroy the house of Jacob, saith the LORD.","ref":"Amos 9:8","synthesized":"Surely the eyes of the Lord GOD are on the sinful kingdom, and I will destroy it from the face of the earth. Yet I will not utterly destroy the house of Jacob,” declares the LORD.","sources":{"KJV":{"text":"Behold, the eyes of the Lord GOD are upon the sinful kingdom, and I will destroy it from off the face of the earth; saving that I will not utterly destroy the house of Jacob, saith the LORD."},"BSB":{"text":"Surely the eyes of the Lord GOD are on the sinful kingdom, and I will destroy it from the face of the earth. Yet I will not utterly destroy the house of Jacob,” declares the LORD."}},"definableWords":["Lord","God","kingdom","earth","house","Jacob","LORD"],"peopleInVerse":["Jacob"]},"9":{"text":"For, lo, I will command, and I will sift the house of Israel among all nations, like as corn is sifted in a sieve, yet shall not the least grain fall upon the earth.","ref":"Amos 9:9","synthesized":"“For surely I will give the command, and I will shake the house of Israel among all the nations as grain is sifted in a sieve; but not a pebble will reach the ground.","sources":{"KJV":{"text":"For, lo, I will command, and I will sift the house of Israel among all nations, like as corn is sifted in a sieve, yet shall not the least grain fall upon the earth."},"BSB":{"text":"“For surely I will give the command, and I will shake the house of Israel among all the nations as grain is sifted in a sieve; but not a pebble will reach the ground."}},"definableWords":["house","Israel","nations","ground"],"peopleInVerse":[]},"10":{"text":"All the sinners of my people shall die by the sword, which say, The evil shall not overtake nor prevent us.","ref":"Amos 9:10","synthesized":"All the sinners among My people will die by the sword— all those who say, ‘Disaster will never draw near or confront us.’”","sources":{"KJV":{"text":"All the sinners of my people shall die by the sword, which say, The evil shall not overtake nor prevent us."},"BSB":{"text":"All the sinners among My people will die by the sword— all those who say, ‘Disaster will never draw near or confront us.’”"}},"definableWords":["people","die","or"],"peopleInVerse":[]},"11":{"text":"In that day will I raise up the tabernacle of David that is fallen, and close up the breaches thereof; and I will raise up his ruins, and I will build it as in the days of old:","ref":"Amos 9:11","synthesized":"“In that day I will restore the fallen tent of David. I will repair its gaps, restore its ruins, and rebuild it as in the days of old,","sources":{"KJV":{"text":"In that day will I raise up the tabernacle of David that is fallen, and close up the breaches thereof; and I will raise up his ruins, and I will build it as in the days of old:"},"BSB":{"text":"“In that day I will restore the fallen tent of David. I will repair its gaps, restore its ruins, and rebuild it as in the days of old,"}},"definableWords":["day","days"],"peopleInVerse":["David"]},"12":{"text":"That they may possess the remnant of Edom, and of all the heathen, which are called by my name, saith the LORD that doeth this.","ref":"Amos 9:12","synthesized":"that they may possess the remnant of Edom and all the nations that bear My name,” declares the LORD, who will do this.","sources":{"KJV":{"text":"That they may possess the remnant of Edom, and of all the heathen, which are called by my name, saith the LORD that doeth this."},"BSB":{"text":"that they may possess the remnant of Edom and all the nations that bear My name,” declares the LORD, who will do this."}},"definableWords":["remnant","Edom","nations","name","LORD"],"peopleInVerse":[]},"13":{"text":"Behold, the days come, saith the LORD, that the plowman shall overtake the reaper, and the treader of grapes him that soweth seed; and the mountains shall drop sweet wine, and all the hills shall melt.","ref":"Amos 9:13","synthesized":"“Behold, the days are coming,” declares the LORD, “when the plowman will overtake the reaper and the treader of grapes, the sower of seed. The mountains will drip with sweet wine, with which all the hills will flow.","sources":{"KJV":{"text":"Behold, the days come, saith the LORD, that the plowman shall overtake the reaper, and the treader of grapes him that soweth seed; and the mountains shall drop sweet wine, and all the hills shall melt."},"BSB":{"text":"“Behold, the days are coming,” declares the LORD, “when the plowman will overtake the reaper and the treader of grapes, the sower of seed. The mountains will drip with sweet wine, with which all the hills will flow."}},"definableWords":["days","LORD","seed"],"peopleInVerse":[]},"14":{"text":"And I will bring again the captivity of my people of Israel, and they shall build the waste cities, and inhabit them; and they shall plant vineyards, and drink the wine thereof; they shall also make gardens, and eat the fruit of them.","ref":"Amos 9:14","synthesized":"I will restore My people Israel from captivity; they will rebuild and inhabit the ruined cities. They will plant vineyards and drink their wine; they will make gardens and eat their fruit.","sources":{"KJV":{"text":"And I will bring again the captivity of my people of Israel, and they shall build the waste cities, and inhabit them; and they shall plant vineyards, and drink the wine thereof; they shall also make gardens, and eat the fruit of them."},"BSB":{"text":"I will restore My people Israel from captivity; they will rebuild and inhabit the ruined cities. They will plant vineyards and drink their wine; they will make gardens and eat their fruit."}},"definableWords":["people","Israel","make"],"peopleInVerse":[]},"15":{"text":"And I will plant them upon their land, and they shall no more be pulled up out of their land which I have given them, saith the LORD thy God.","ref":"Amos 9:15","synthesized":"I will firmly plant them in their own land, never again to be uprooted from the land that I have given them,” says the LORD your God.","sources":{"KJV":{"text":"And I will plant them upon their land, and they shall no more be pulled up out of their land which I have given them, saith the LORD thy God."},"BSB":{"text":"I will firmly plant them in their own land, never again to be uprooted from the land that I have given them,” says the LORD your God."}},"definableWords":["land","LORD","God"],"peopleInVerse":[]}}}};